import React from 'react';
import { FileText, ArrowRight } from 'lucide-react';
import BasicForm from './BasicForm';

const FormsPage = () => {
  return (
    <div className="container mx-auto px-4 py-8">
      <div className="max-w-4xl mx-auto">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
            Legal Forms
          </h1>
          <p className="text-gray-600 dark:text-gray-300">
            Complete and submit legal forms efficiently. Please ensure all information is accurate before submission.
          </p>
        </div>

        <div className="grid gap-6 md:grid-cols-2">
          <FormCard
            title="Document Filing Form"
            description="Submit essential documentation for legal proceedings"
            icon={FileText}
            active={true}
            onClick={() => console.log('Navigating to form')}
          />
          <FormCard
            title="Additional Forms"
            description="More legal forms will be available soon"
            icon={FileText}
            disabled={true}
          />
        </div>

        <div className="mt-8">
          <BasicForm />
        </div>
      </div>
    </div>
  );
};

const FormCard = ({ title, description, icon: Icon, active, disabled, onClick }) => {
  return (
    <div className={`p-6 rounded-lg border ${
      disabled 
        ? 'bg-gray-50 border-gray-200 dark:bg-gray-800 dark:border-gray-700' 
        : 'bg-white border-gray-200 dark:bg-gray-800 dark:border-gray-700 hover:border-blue-500 dark:hover:border-blue-500 transition-colors'
    }`}>
      <div className="flex items-start space-x-4">
        <div className="flex-shrink-0">
          <Icon className={`h-6 w-6 ${
            disabled 
              ? 'text-gray-400' 
              : 'text-blue-500'
          }`} />
        </div>
        <div className="flex-1">
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-1">
            {title}
          </h3>
          <p className="text-gray-600 dark:text-gray-300 text-sm">
            {description}
          </p>
          
          {!disabled && (
            <button
              onClick={onClick}
              className="mt-4 inline-flex items-center text-sm text-blue-600 hover:text-blue-700 dark:text-blue-400 dark:hover:text-blue-300"
            >
              Access form
              <ArrowRight className="ml-2 h-4 w-4" />
            </button>
          )}
          
          {disabled && (
            <span className="mt-4 inline-flex items-center text-sm text-gray-500 dark:text-gray-400">
              Coming Soon
            </span>
          )}
        </div>
      </div>
    </div>
  );
};

export default FormsPage;
